```typescript
import { Effect, Context, Layer } from "effect";

interface Config {
  readonly apiUrl: string;
  readonly timeoutMs: number;
}

const Config = Context.GenericTag<Config>("app/Config");

const program: Effect.Effect<string, never, Config> = Effect.gen(function* () {
  const cfg = yield* Config;
  return `${cfg.apiUrl}?t=${cfg.timeoutMs}`;
});

const ConfigLive = Layer.succeed(Config, {
  apiUrl: "https://api.example.com",
  timeoutMs: 5000,
});

export const main = Effect.runPromise(program.pipe(Effect.provide(ConfigLive)));
```

The identifier string `"app/Config"` is mandatory in v3 — it drives service identity and also shows up in error messages when a Layer is missing.

```typescript
import { Effect, Context, Layer } from "effect";

interface Logger {
  readonly info: (msg: string) => Effect.Effect<void>;
}

const Logger = Context.GenericTag<Logger>("app/Logger");

const program: Effect.Effect<void, never, Logger> = Effect.gen(function* () {
  const log = yield* Logger;
  yield* log.info("hi");
});

const LoggerLive = Layer.succeed(Logger, {
  info: (msg) => Effect.sync(() => console.log(`[info] ${msg}`)),
});

export const runnable = program.pipe(Effect.provide(LoggerLive));
```

Two v2→v3 deltas: `Context.Tag<T>()` becomes `Context.GenericTag<T>("scope/Name")` — the identifier string is mandatory — and a two-step `flatMap` reads better as `Effect.gen` with `yield*`.

```typescript
import { Effect, Context, Layer } from "effect";

interface Db {
  readonly count: Effect.Effect<number>;
}

const Db = Context.GenericTag<Db>("app/Db");

const program: Effect.Effect<number, never, Db> = Effect.gen(function* () {
  const db = yield* Db;
  return yield* db.count;
});

const DbLive = Layer.succeed(Db, { count: Effect.succeed(42) });

export const runnable = program.pipe(Effect.provide(DbLive));
```

`Effect.service(Tag)` was removed in v3; accessing a tagged service is now just `yield* Tag` inside `Effect.gen` (or `Effect.flatMap(Tag, ...)` for one-liners).

```typescript
import { Effect, Context, Layer } from "effect";

interface User {
  readonly id: string;
  readonly name: string;
}

interface Auth {
  readonly login: (u: string) => Effect.Effect<string>;
  readonly currentUser: Effect.Effect<User>;
}

const Auth = Context.GenericTag<Auth>("app/Auth");

const AuthLive = Layer.succeed(Auth, {
  login: (u) => Effect.succeed(`token:${u}`),
  currentUser: Effect.succeed({ id: "1", name: "zoe" }),
});

export const program: Effect.Effect<User, never, Auth> = Effect.gen(function* () {
  const auth = yield* Auth;
  return yield* auth.currentUser;
});

export const runnable = program.pipe(Effect.provide(AuthLive));
```

`currentUser` is a value (not a thunk) because the effect itself is lazy — referencing it repeatedly re-runs the effect.

```typescript
import { Effect, Context, Layer } from "effect";

interface Clock {
  readonly now: Effect.Effect<number>;
}
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Metrics {
  readonly record: (name: string) => Effect.Effect<void>;
}
const Metrics = Context.GenericTag<Metrics>("app/Metrics");

const ClockLive = Layer.succeed(Clock, { now: Effect.sync(() => Date.now()) });

const MetricsLive = Layer.effect(
  Metrics,
  Effect.gen(function* () {
    const clock = yield* Clock;
    return {
      record: (name) =>
        Effect.gen(function* () {
          const t = yield* clock.now;
          yield* Effect.sync(() => console.log(`${name}@${t}`));
        }),
    };
  })
);

export const AppLayer = Layer.provide(MetricsLive, ClockLive);
```

`Layer.effect(Tag, buildEff)` lets the builder `yield* Clock`, so Metrics' dependency on Clock is tracked in its type. `Layer.provide(inner, outer)` wires outer into inner.

```typescript
