The identifier argument (`"app/HttpClient"`) is mandatory in v3; without it, two structurally identical tags would collide in the Context.

```typescript
import { Effect, Context, Layer } from "effect";

interface Cache {
  readonly get: (key: string) => Effect.Effect<string | null>;
  readonly set: (key: string, value: string) => Effect.Effect<void>;
}

const Cache = Context.GenericTag<Cache>("app/Cache");

const CacheLive = Layer.effect(
  Cache,
  Effect.sync(() => {
    const store = new Map<string, string>();
    return {
      get: (key) => Effect.sync(() => store.get(key) ?? null),
      set: (key, value) => Effect.sync(() => void store.set(key, value)),
    };
  })
);

export const program: Effect.Effect<string | null, never, Cache> = Effect.gen(function* () {
  const cache = yield* Cache;
  yield* cache.set("k", "v");
  return yield* cache.get("k");
});

export const runnable = program.pipe(Effect.provide(CacheLive));
```

The `Map` lives in the closure returned by `Layer.effect`'s builder — a single instance per layer construction, which is what you usually want.

```typescript
import { Effect, Context, Layer } from "effect";

interface Config {
  readonly apiUrl: string;
}

const Config = Context.GenericTag<Config>("app/Config");

const ConfigLive = Layer.effect(
  Config,
  Effect.sync(() => ({ apiUrl: process.env.API_URL ?? "dev" }))
);

export const program: Effect.Effect<string, never, Config> = Effect.gen(function* () {
  const cfg = yield* Config;
  return cfg.apiUrl;
});

export const runnable = program.pipe(Effect.provide(ConfigLive));
```

Pulling env lookup into a Layer makes the program deterministic — tests can swap `ConfigLive` for `Layer.succeed(Config, { apiUrl: "test" })` without touching `process.env`.

A `Context.GenericTag<Service>("scope/Name")` creates a typed handle to a service slot in the Effect runtime's `Context`. Inside `Effect.gen`, `yield* Tag` resolves the implementation or — if no Layer provides it — a compile error surfaces through the `R` (requirements) channel of `Effect<A, E, R>`.

```typescript
import { Effect, Context, Layer } from "effect";

interface Random {
  readonly int: (max: number) => Effect.Effect<number>;
}

const Random = Context.GenericTag<Random>("app/Random");

const RandomLive = Layer.succeed(Random, {
  int: (max) => Effect.sync(() => Math.floor(Math.random() * max)),
});

const program: Effect.Effect<number, never, Random> = Effect.gen(function* () {
  const rnd = yield* Random;
  const a = yield* rnd.int(10);
  const b = yield* rnd.int(10);
  return a + b;
});

export const runnable = program.pipe(Effect.provide(RandomLive));
```

The `R` channel carries `Random` until `Effect.provide(RandomLive)` discharges it.

```typescript
import { Effect, Context, Layer } from "effect";

interface Metrics {
  readonly timed: <A, E, R>(name: string, eff: Effect.Effect<A, E, R>) => Effect.Effect<A, E, R>;
}

const Metrics = Context.GenericTag<Metrics>("app/Metrics");

const MetricsLive = Layer.succeed(Metrics, {
  timed: (name, eff) =>
    Effect.gen(function* () {
      const t0 = yield* Effect.sync(() => Date.now());
      const a = yield* eff;
      const dt = yield* Effect.sync(() => Date.now() - t0);
      yield* Effect.sync(() => console.log(`${name} took ${dt}ms`));
      return a;
    }),
});

const fetchData: Effect.Effect<string, never, never> = Effect.succeed("ok");

export const program: Effect.Effect<string, never, Metrics> = Effect.gen(function* () {
  const metrics = yield* Metrics;
  return yield* metrics.timed("fetch", fetchData);
});

export const runnable = program.pipe(Effect.provide(MetricsLive));
```

Because `timed` is generic over `<A, E, R>`, the requirements of `eff` bubble up naturally into the final program's `R` channel.

```typescript
import { Effect, Context, Layer } from "effect";

interface FileSystem {
  readonly read: (path: string) => Effect.Effect<string>;
  readonly write: (path: string, data: string) => Effect.Effect<void>;
}

const FileSystem = Context.GenericTag<FileSystem>("app/FileSystem");

const FileSystemLive = Layer.effect(
  FileSystem,
  Effect.sync(() => {
    const store = new Map<string, string>();
    return {
      read: (p) => Effect.sync(() => store.get(p) ?? ""),
      write: (p, d) => Effect.sync(() => void store.set(p, d)),
    };
  })
);

export const program: Effect.Effect<string, never, FileSystem> = Effect.gen(function* () {
  const fs = yield* FileSystem;
  yield* fs.write("/tmp/greet", "hi");
  return yield* fs.read("/tmp/greet");
});

export const runnable = program.pipe(Effect.provide(FileSystemLive));
```

The in-memory `Map` is an easy test double — swap `FileSystemLive` for a node:fs-backed Layer in production without changing the program.

```typescript
import { Effect, Context, Layer } from "effect";

interface Env {
