```typescript
import { Effect, Context, Layer } from "effect";

interface RateLimiter {
  readonly acquire: (key: string) => Effect.Effect<boolean>;
}

const RateLimiter = Context.GenericTag<RateLimiter>("app/RateLimiter");

const RateLimiterLive = Layer.effect(
