The counter state is encapsulated in the `Layer.effect` builder's closure — each layer build gets a fresh counter, which is what tests want.

```typescript
import { Effect, Context, Layer } from "effect";

interface HttpClient {
  readonly getText: (url: string) => Effect.Effect<string, Error>;
}

const HttpClient = Context.GenericTag<HttpClient>("app/HttpClient");

const HttpClientLive = Layer.succeed(HttpClient, {
  getText: (url) =>
    Effect.tryPromise({
      try: () => fetch(url).then((r) => r.text()),
      catch: (u) => (u instanceof Error ? u : new Error(String(u))),
    }),
