Inlining `fetch` hard-codes the network into the program type; routing it through a service keeps tests hermetic and the `R` channel honest.

Each service has a tag (`Context.GenericTag<T>("scope/Name")`) and a Layer that builds the implementation. `Layer.merge` combines layers with disjoint provides; `Layer.provide(inner, outer)` discharges inner's dependency on outer. The final `Effect.provide(program, AppLayer)` drains the `R` channel.

```typescript
import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: Effect.Effect<number> }
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Logger { readonly info: (m: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

const ClockLive = Layer.succeed(Clock, { now: Effect.sync(() => Date.now()) });
const LoggerLive = Layer.succeed(Logger, {
  info: (m) => Effect.sync(() => console.log(m)),
});

const AppLayer = Layer.merge(ClockLive, LoggerLive);

const program: Effect.Effect<void, never, Clock | Logger> = Effect.gen(function* () {
  const clock = yield* Clock;
  const log = yield* Logger;
  const t = yield* clock.now;
  yield* log.info(`t=${t}`);
});

export const runnable = program.pipe(Effect.provide(AppLayer));
```

`Clock | Logger` in the `R` channel becomes `never` once `AppLayer` is provided.

```typescript
import { Effect, Data } from "effect";

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

const fetchBody = (url: string): Effect.Effect<string, NetworkError> =>
  Effect.tryPromise({
    try: () => fetch(url).then((r) => r.text()),
    catch: (cause) => new NetworkError({ cause }),
  });

const parseInt10 = (s: string): Effect.Effect<number, ParseError> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n)
    ? Effect.fail(new ParseError({ raw: s }))
    : Effect.succeed(n);
};

export const program: Effect.Effect<number, ParseError> = Effect.gen(function* () {
  const body = yield* fetchBody("/count");
  return yield* parseInt10(body);
}).pipe(Effect.catchTag("NetworkError", () => Effect.succeed("0").pipe(Effect.flatMap(parseInt10))));
```

`Effect.catchTag` takes the `_tag` **string** (not the class reference). Once `NetworkError` is caught, only `ParseError` remains in the error channel.

```typescript
import { Effect, Data } from "effect";

class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

const query = (sql: string): Effect.Effect<readonly unknown[], DbError> =>
  Effect.tryPromise({
    try: async () => {
      if (!sql) throw new Error("empty sql");
      return [] as readonly unknown[];
    },
    catch: (cause) => new DbError({ cause }),
  });

export const program: Effect.Effect<number, never> = query("select 1").pipe(
  Effect.map((rows) => rows.length),
  Effect.catchTag("DbError", (e) => Effect.sync(() => {
    console.error("db fail", e.cause);
    return 0;
  }))
);
```

v3 prefers tagged-error classes over raw `Error` — `Effect.catchTag("DbError", ...)` can then discriminate on `_tag` and narrow `e` to `DbError` with a typed `cause` field.

```typescript
import { Effect, Data } from "effect";

class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}
class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

const find = (id: string): Effect.Effect<string, NotFoundError | DbError> =>
  id === "" ? Effect.fail(new NotFoundError({ id })) : Effect.succeed("row");

export const program: Effect.Effect<string | null, DbError> = find("").pipe(
  Effect.catchTag("NotFoundError", () => Effect.succeed(null))
);
```

String-matching on `.message` is fragile — tagging errors with `Data.TaggedError` gives `Effect.catchTag` a real discriminator and removes the caught case from the error channel.

```typescript
import { Effect, Data, Schedule, Duration } from "effect";

interface User { readonly id: string; readonly name: string }

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}

declare const fetchUserRaw: (id: string) => Effect.Effect<User, NetworkError | NotFoundError>;

const backoff = Schedule.exponential(Duration.millis(100)).pipe(Schedule.compose(Schedule.recurs(3)));

export const fetchUser = (id: string): Effect.Effect<User, NotFoundError> =>
  fetchUserRaw(id).pipe(
    Effect.retry({ schedule: backoff, while: (e) => e._tag === "NetworkError" }),
    Effect.catchTag("NetworkError", (e) => Effect.die(e))
  );
```

The `while` guard on `Effect.retry` uses `_tag` to retry only on `NetworkError`; after the bounded schedule is exhausted, the remaining `NetworkError` is promoted to a defect with `Effect.die`, leaving `NotFoundError` in the error channel.

```typescript
import { Effect, Data } from "effect";

class AuthError extends Data.TaggedError("AuthError")<{ readonly reason: string }> {}
class RateLimited extends Data.TaggedError("RateLimited")<{ readonly retryAfter: number }> {}

const op: Effect.Effect<string, AuthError | RateLimited> = Effect.fail(
  new RateLimited({ retryAfter: 3 })
);

export const handled: Effect.Effect<string, AuthError> = op.pipe(
  Effect.catchTag("RateLimited", (e) => Effect.succeed(`retry in ${e.retryAfter}s`))
);
```

`Effect.catchTag("RateLimited", ...)` subtracts `RateLimited` from the error channel — `handled`'s `E` is now just `AuthError`, because the caught branch returned a success.

```typescript
import { Effect, Data } from "effect";

class BoomError extends Data.TaggedError("BoomError")<{ readonly detail: string }> {}

const op: Effect.Effect<number, BoomError> = Effect.fail(new BoomError({ detail: "boom" }));

export const recovered: Effect.Effect<number, never> = op.pipe(
  Effect.catchTag("BoomError", (e) => Effect.succeed(e.detail.length))
);
```

Generic `Error` gives you nothing typed in the `E` channel; `Data.TaggedError("BoomError")` gives `catchTag` a real discriminator and carries structured fields.

```typescript
import { Effect, Data } from "effect";

class EmptyField extends Data.TaggedError("EmptyField")<{ readonly field: string }> {}
class BadEmail extends Data.TaggedError("BadEmail")<{ readonly value: string }> {}

interface Signup { readonly name: string; readonly email: string }

const nonEmpty = (field: string, value: string): Effect.Effect<string, EmptyField> =>
  value.trim().length > 0 ? Effect.succeed(value) : Effect.fail(new EmptyField({ field }));

const validEmail = (value: string): Effect.Effect<string, BadEmail> =>
  value.includes("@") ? Effect.succeed(value) : Effect.fail(new BadEmail({ value }));

export const validate = (raw: Signup): Effect.Effect<Signup, EmptyField | BadEmail> =>
  Effect.gen(function* () {
    const name = yield* nonEmpty("name", raw.name);
    const email = yield* nonEmpty("email", raw.email);
    const okEmail = yield* validEmail(email);
    return { name, email: okEmail };
  });
```

Each validator returns an `Effect<A, TaggedError>`; composing them in `Effect.gen` unions the error channel to `EmptyField | BadEmail`, which `catchTag` can later discriminate.

```typescript
import { Effect, Data } from "effect";

class FooErr extends Data.TaggedError("FooErr")<{ readonly msg: string }> {}
class BarErr extends Data.TaggedError("BarErr")<{ readonly code: number }> {}

const op = (x: number): Effect.Effect<number, FooErr | BarErr> =>
  x < 0
    ? Effect.fail(new FooErr({ msg: "negative" }))
    : x > 100
      ? Effect.fail(new BarErr({ code: x }))
      : Effect.succeed(x);

export const handled: Effect.Effect<number, BarErr> = op(-1).pipe(
  Effect.catchTag("FooErr", () => Effect.succeed(0))
);
```

`Data.TaggedError` gives you structural equality, a stable `_tag`, and auto-generated constructors — same shape as the hand-rolled class, one import instead of boilerplate.

`Effect.catchTag(tagString, handler)` removes the matched tag from the error channel if the handler returns a success, or replaces it with the handler's own error type if the handler re-fails. The discriminator is the string `_tag`, not the class itself, so this works for both `Data.TaggedError` and hand-rolled `{ readonly _tag: "..." }` shapes.

```typescript
import { Effect, Data } from "effect";

class NotFound extends Data.TaggedError("NotFound")<{ readonly id: string }> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly role: string }> {}

const load = (id: string): Effect.Effect<string, NotFound | Forbidden> =>
  id === ""
    ? Effect.fail(new NotFound({ id }))
    : Effect.fail(new Forbidden({ role: "guest" }));

export const handled: Effect.Effect<string, Forbidden> = load("").pipe(
  Effect.catchTag("NotFound", (e) => Effect.succeed(`missing:${e.id}`))
);
```

The resulting `E` is `Forbidden` only — `NotFound` is gone because the handler's success drained it.

```typescript
import { Effect, Data } from "effect";

class FileMissing extends Data.TaggedError("FileMissing")<{ readonly path: string }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

interface Config { readonly apiUrl: string }

const read = (path: string): Effect.Effect<string, FileMissing> =>
  path.endsWith(".json")
    ? Effect.succeed('{"apiUrl":"x"}')
    : Effect.fail(new FileMissing({ path }));

const parse = (raw: string): Effect.Effect<Config, ParseError> =>
  Effect.try({
    try: () => JSON.parse(raw) as Config,
    catch: () => new ParseError({ raw }),
  });

export const load = (path: string): Effect.Effect<Config, ParseError> =>
  Effect.gen(function* () {
    const raw = yield* read(path);
    return yield* parse(raw);
  }).pipe(
    Effect.catchTag("FileMissing", () => Effect.succeed({ apiUrl: "default" }))
  );
```

`FileMissing` is swallowed into a default value; `ParseError` stays in the channel because the caller probably wants to see malformed configs.

```typescript
import { Effect, Data } from "effect";

class CardDeclined extends Data.TaggedError("CardDeclined")<{ readonly reason: string }> {}
class GatewayDown extends Data.TaggedError("GatewayDown")<{ readonly cause: unknown }> {}
class Fraud extends Data.TaggedError("Fraud")<{ readonly score: number }> {}

const charge = (amount: number): Effect.Effect<string, CardDeclined | GatewayDown | Fraud> => {
  if (amount <= 0) return Effect.fail(new CardDeclined({ reason: "bad amount" }));
  if (amount > 10_000) return Effect.fail(new Fraud({ score: 99 }));
  return Effect.succeed("ch_123");
};

export const handled: Effect.Effect<string, Fraud> = charge(50).pipe(
  Effect.catchTag("CardDeclined", (e) => Effect.succeed(`declined:${e.reason}`)),
  Effect.catchTag("GatewayDown", (_e) => Effect.succeed("retry-later"))
);
```

Two `catchTag` calls discharge two of the three errors; `Fraud` remains in the channel because the caller should decide whether to escalate it.

```typescript
import { Effect, Data } from "effect";

class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly afterMs: number }> {}

const awaitReply = (ms: number): Effect.Effect<string, TimeoutError> =>
  ms > 1000
    ? Effect.fail(new TimeoutError({ afterMs: ms }))
    : Effect.succeed("pong");

export const handled: Effect.Effect<string, never> = awaitReply(2000).pipe(
  Effect.catchTag("TimeoutError", (e) => Effect.succeed(`gave up after ${e.afterMs}ms`))
