`Effect.fail(new Error(...))` produces an opaque `Error` in the channel — you lose discrimination and structured fields. `Data.TaggedError` gives you both.

```typescript
import { Effect, Data } from "effect";

interface User { readonly id: string }

class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

declare const listUsersRaw: Effect.Effect<readonly User[], DbError>;

export const listUsers: Effect.Effect<readonly User[], never> = listUsersRaw.pipe(
  Effect.catchTag("DbError", (e) =>
    Effect.sync(() => {
      console.warn("db down", e.cause);
      return [] as readonly User[];
    })
  )
);
```

The handler returns `Effect<readonly User[], never>`, which drains `DbError` from the channel — the final `E` is `never`, so callers don't need a `.catch` at all.

```typescript
import { Effect, Data } from "effect";

class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

const parseNum = (raw: string): Effect.Effect<number, ParseError> => {
  const n = Number(raw);
  return Number.isNaN(n) ? Effect.fail(new ParseError({ raw })) : Effect.succeed(n);
};

export const parseOrZero = (raw: string): Effect.Effect<number, never> =>
  parseNum(raw).pipe(Effect.catchTag("ParseError", () => Effect.succeed(0)));
```

Two deltas: the error is a tagged class (not a raw `Error`), and `catchAll` becomes `catchTag("ParseError", ...)` so only that tag is caught — any other error in the channel would survive.

```typescript
import { Effect, Data } from "effect";

class StepAError extends Data.TaggedError("StepAError")<{ readonly msg: string }> {}
class StepBError extends Data.TaggedError("StepBError")<{ readonly code: number }> {}

const stepA: Effect.Effect<number, StepAError> = Effect.fail(new StepAError({ msg: "nope" }));
const stepB = (n: number): Effect.Effect<string, StepBError> =>
  n > 0 ? Effect.succeed(`ok-${n}`) : Effect.fail(new StepBError({ code: -1 }));

const program: Effect.Effect<string, StepAError | StepBError> = Effect.gen(function* () {
  const n = yield* stepA;
  return yield* stepB(n);
});

export const handled: Effect.Effect<string, never> = program.pipe(
  Effect.catchTag("StepAError", () => Effect.succeed("recovered-A")),
  Effect.catchTag("StepBError", () => Effect.succeed("recovered-B"))
);
```

Chaining `Effect.catchTag` calls narrows the error union tag by tag — order doesn't matter for correctness since each match is on a distinct discriminator.

