```typescript
import { Effect, Data } from "effect";

class TooLarge extends Data.TaggedError("TooLarge")<{ readonly bytes: number }> {}
class BadType extends Data.TaggedError("BadType")<{ readonly mime: string }> {}
class UploadFailed extends Data.TaggedError("UploadFailed")<{ readonly cause: unknown }> {}

interface UploadInput { readonly bytes: number; readonly mime: string }

const validate = (i: UploadInput): Effect.Effect<UploadInput, TooLarge | BadType> => {
  if (i.bytes > 10_000_000) return Effect.fail(new TooLarge({ bytes: i.bytes }));
  if (!i.mime.startsWith("image/")) return Effect.fail(new BadType({ mime: i.mime }));
  return Effect.succeed(i);
};

const send = (_i: UploadInput): Effect.Effect<string, UploadFailed> =>
  Effect.succeed("uploaded");

export const upload = (i: UploadInput): Effect.Effect<string, TooLarge | BadType | UploadFailed> =>
  validate(i).pipe(Effect.flatMap(send));

export const handled: Effect.Effect<string, UploadFailed> = upload({ bytes: 99, mime: "image/png" }).pipe(
  Effect.catchTag("TooLarge", (e) => Effect.succeed(`reject:${e.bytes}`)),
  Effect.catchTag("BadType", (e) => Effect.succeed(`reject:${e.mime}`))
);
```

Client-side validation errors (`TooLarge`, `BadType`) are surfaced as user-facing strings; `UploadFailed` stays in the channel for the outer layer to retry or log.

```typescript
import { Effect, Data } from "effect";

class NegativeInput extends Data.TaggedError("NegativeInput")<{ readonly value: number }> {}

const op = (x: number): Effect.Effect<number, NegativeInput> =>
  x > 0 ? Effect.succeed(x) : Effect.fail(new NegativeInput({ value: x }));

